import os
out_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "scripts", "bogus.ques.ru")
with open(out_path, "w", encoding="utf-8", newline="\r\n") as f:
    for line in Q:
        f.write(line + "\n")
print(f"Wrote {len(Q)} questions to {out_path}")
